/**
 * Notification model and related types.
 *
 * All notification types, payloads, and delivery channel definitions
 * for the event-driven notification system.
 */

/**
 * Supported notification channels. Each channel has a corresponding
 * adapter that implements the NotificationAdapter interface.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app';

/**
 * Notification delivery priority.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * Categorizes the kind of notification being sent.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_update';

/**
 * The payload that an adapter receives to deliver a notification.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  metadata?: Record<string, string>;
}

/**
 * Result of a notification delivery attempt by an adapter.
 */
export interface NotificationResult {
  success: boolean;
  channel: NotificationChannel;
  error?: string;
  deliveredAt?: Date;
}

/**
 * A persisted notification record.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  status: 'pending' | 'sent' | 'failed';
  error?: string;
  createdAt: Date;
  sentAt?: Date;
}

/**
 * Base interface for all notification delivery adapters.
 *
 * CONSTRAINT: All notification channels (email, webhook, in-app, SMS, etc.)
 * must implement this interface. The NotificationService dispatches to
 * adapters by channel — it never sends directly.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create an adapter implementing NotificationAdapter in src/adapters/
 * 3. Register the adapter with NotificationService.registerAdapter()
 */

import type { NotificationPayload, NotificationResult, NotificationChannel } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must return a result indicating success or failure — never throw.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Delivers notifications via email. Currently a stub implementation
 * that logs sends in-memory. Replace the send() body with a real
 * email provider (SendGrid, SES, SMTP, etc.) when ready.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ payload: NotificationPayload; sentAt: Date }> = [];

  /**
   * Send a notification via email.
   *
   * Stub implementation: records the send in memory and always succeeds.
   * Replace with real email provider integration for production.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    // Stub: record the send
    this.sentEmails.push({ payload, sentAt: new Date() });

    return {
      success: true,
      channel: 'email',
      deliveredAt: new Date(),
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): Array<{ payload: NotificationPayload; sentAt: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Event-driven, adapter-based.
 *
 * Flow: EventBus events → NotificationService (subscriber) → NotificationAdapter (delivery)
 *
 * ALL notifications flow through this pipeline:
 * 1. A service emits a typed event via EventBus.emit()
 * 2. NotificationService receives the event via its EventBus subscriptions
 * 3. NotificationService builds a NotificationPayload from the event
 * 4. The payload is dispatched to the registered adapter for the target channel
 *
 * Constraints:
 * - All event subscriptions use EventBus — no CallbackRegistry or direct calls
 * - All delivery goes through NotificationAdapter implementations
 * - New channels require only a new adapter registered via registerAdapter()
 * - New event types require only a new EventBus subscription in registerHandlers()
 *
 * Depends on:
 * - EventBus (event system) for receiving ALL events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a delivery adapter for a notification channel.
   * Only one adapter per channel — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Register event handlers for notification triggers.
   *
   * All subscriptions go through EventBus — this is the single entry point
   * for all notification-triggering events.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.sendNotification({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      priority: 'normal',
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   *
   * If an adapter is registered for the channel, the notification is
   * delivered through it. If no adapter is registered, the notification
   * is still recorded (with 'sent' status) for backward compatibility
   * and testing without adapters.
   */
  private async sendNotification(params: {
    type: NotificationType;
    recipient: string;
    subject: string;
    body: string;
    channel: NotificationChannel;
    priority: NotificationPayload['priority'];
    metadata?: Record<string, string>;
  }): Promise<void> {
    const notification: Notification = {
      id: generateNotificationId(),
      type: params.type,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      channel: params.channel,
      priority: params.priority,
      status: 'pending',
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(params.channel);
    if (adapter) {
      const payload: NotificationPayload = {
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        channel: params.channel,
        priority: params.priority,
        metadata: params.metadata,
      };

      const result = await adapter.send(payload);
      notification.status = result.success ? 'sent' : 'failed';
      notification.error = result.error;
      notification.sentAt = result.deliveredAt;
    } else {
      // No adapter registered — record notification as sent (useful for testing)
      notification.status = 'sent';
      notification.sentAt = new Date();
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.status}: ${notification.id} to ${params.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

